# Read the knowledge articles from the file
with open('file_storage/functions.query_db:14.json', 'r') as f:
    knowledge_articles = json.load(f)

# Find the article about product quantity limits
quantity_limit_article = None
for article in knowledge_articles:
    if 'product quantity' in article['title'].lower() or 'quantity limits' in article['title'].lower():
        quantity_limit_article = article
        break

# Extract product limits from the article
import re
product_limits = {}
if quantity_limit_article:
    text = quantity_limit_article.get('faq_answer__c', '') + quantity_limit_article.get('summary', '')
    lines = text.split('\n')
    for line in lines:
        if ' - ' in line and 'up to' in line:
            # Extract product name and limit
            match = re.search(r'\*\*([^*]+)\*\*.*up to (\d+)', line)
            if match:
                product_name = match.group(1).strip()
                limit = int(match.group(2))
                product_limits[product_name] = limit

print("__RESULT__:")
print(json.dumps({
    "quantity_limit_article_id": quantity_limit_article['id'] if quantity_limit_article else None,
    "product_limits": product_limits
}, indent=2))"} <|tool_calls_section_end|>

